function updateMrKowalski(node) {
  if (!node || typeof node !== "object") return false;
  let changed = false;

  if (Array.isArray(node)) {
    for (const item of node) changed = updateMrKowalski(item) || changed;
    return changed;
  }

  for (const [key, value] of Object.entries(node)) {
    if (key === "mr_kowalski" && typeof value === "string") {
      if (value !== "John Ronald Kowalski") {
        node[key] = "John Ronald Kowalski";
        changed = true;
      }
    } else if (key === "mr_kowalski" && value && typeof value === "object") {
      if (value.full_name !== "John Ronald Kowalski") {
        value.full_name = "John Ronald Kowalski";
        changed = true;
      }
    } else if (value && typeof value === "object") {
      changed = updateMrKowalski(value) || changed;
    }
  }
  return changed;
}

updateMrKowalski(data);

const updated = space.utils.yaml.stringify(data);
return await space.api.fileWrite(path, updated, "utf8");

